import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface BlackjackMessageDTO {
    text: string;
    level: 'info' | 'warn' | 'error';
}

export class BlackjackMessageParser implements IMessageParser {
    private _data: BlackjackMessageDTO | null = null;

    public flush(): boolean {
        this._data = null;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;
        const text = wrapper.readString();
        const level = (wrapper.readString() || 'info') as
            | 'info'
            | 'warn'
            | 'error';
        this._data = { text, level };
        return true;
    }

    public get data(): BlackjackMessageDTO | null {
        return this._data;
    }
}
